import{_ as d,C as h,o as s,c,a4 as i,b as n,w as t,a as r,E as o,a3 as l}from"./chunks/framework.CK8y3JBd.js";const f=JSON.parse('{"title":"Encrypted Transport (CURVE)","description":"","frontmatter":{},"headers":[],"relativePath":"curve.md","filePath":"curve.md","lastUpdated":null}'),p={name:"curve.md"};function g(y,e,k,u,m,v){const a=h("Mermaid");return s(),c("div",null,[e[2]||(e[2]=i(`<h1 id="Encrypted-Transport-CURVE" tabindex="-1">Encrypted Transport (CURVE) <a class="header-anchor" href="#Encrypted-Transport-CURVE" aria-label="Permalink to &quot;Encrypted Transport (CURVE) {#Encrypted-Transport-CURVE}&quot;">​</a></h1><p>A TCP <a href="/Kaimon.jl/previews/PR65/gate#tcp-mode">gate</a> is, by default, an unencrypted remote code-execution endpoint protected only by a bearer <a href="/Kaimon.jl/previews/PR65/security#gate-tcp-authentication">token</a> that travels in the clear. To expose a gate beyond <code>localhost</code> safely, enable <strong>CURVE</strong> — ZMQ&#39;s Curve25519 transport (encryption via libsodium) — for <strong>confidentiality, integrity, and mutual authentication</strong> on the wire.</p><p>CURVE makes an SSH tunnel unnecessary <em>for security</em>. You may still want SSH (or a VPN) for <em>reachability</em> — NAT, firewalls — in which case CURVE simply runs inside it, and the two are complementary rather than redundant.</p><p>Turn it on when starting the gate (see <a href="/Kaimon.jl/previews/PR65/gate#curve-encryption">CURVE Encryption</a> for the full set of flags / env vars / <code>kaimon.toml</code> keys):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonGate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">serve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:tcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, port</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10005</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, curve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)                  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># strict allow-list</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonGate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">serve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:tcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, port</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10005</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, curve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, allow_any</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># pin-only</span></span></code></pre></div><h2 id="Two-directions-of-trust" tabindex="-1">Two directions of trust <a class="header-anchor" href="#Two-directions-of-trust" aria-label="Permalink to &quot;Two directions of trust {#Two-directions-of-trust}&quot;">​</a></h2><p>Like SSH, CURVE authenticates <strong>both</strong> ends, via two independent mechanisms:</p>`,7)),(s(),n(l,null,{default:t(()=>[o(a,{id:"mermaid-19",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20C%20%5B%22Kaimon%20(client)%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20CK%5B%22client.key%3Cbr%2F%3E(own%20keypair)%22%5D%0A%20%20%20%20%20%20%20%20PIN%5B%22known_servers%3Cbr%2F%3E(pinned%20server%20key)%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20S%20%5B%22CURVE%20gate%20(server)%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20SK%5B%22server.key%3Cbr%2F%3E(own%20keypair)%22%5D%0A%20%20%20%20%20%20%20%20ACL%5B%22authorized_clients%3Cbr%2F%3E(allow-list)%22%5D%0A%20%20%20%20end%0A%20%20%20%20PIN%20--%20%22%E2%91%A0%20client%20authenticates%20server%3A%3Cbr%2F%3Eencrypt%20to%20the%20pinned%20server%20key%3Cbr%2F%3E(wrong%20key%20%E2%87%92%20handshake%20fails)%22%20--%3E%20SK%0A%20%20%20%20CK%20--%20%22%E2%91%A1%20server%20authenticates%20client%3A%3Cbr%2F%3Epresent%20client%20pubkey%22%20--%3E%20ACL%0A%20%20%20%20ACL%20-.%20%22ZAP%20check%20(strict%20mode)%3A%3Cbr%2F%3Eon%20the%20list%3F%20200%2C%20else%20400%22%20.-%3E%20C%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[r(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=i('<ol><li><p><strong>The client authenticates the server</strong> with a <em>pinned</em> public key. CURVE has no in-band key exchange, so the client must already hold the server&#39;s public key <em>before</em> connecting; a server presenting a different key simply fails the handshake (MITM-safe). How that pin is established — and its one weak spot — is covered in <a href="/Kaimon.jl/previews/PR65/curve#tofu-and-soy-free-mode">TOFU and soy-free mode</a>.</p></li><li><p><strong>The server authenticates the client</strong> with an allow-list, via the ZMQ <strong>ZAP</strong> mechanism. Two postures, set by <code>allow_any</code>:</p></li></ol><ul><li><p><strong><code>allow_any=true</code></strong> (pin-only) — encryption + server pinning; any client that holds the server key may connect.</p></li><li><p><strong><code>allow_any=false</code></strong> (default, strict) — each connecting client&#39;s public key must be on the allow-list; an empty list is <strong>fail-closed</strong> (nobody). This is full mutual authentication.</p></li></ul><p>The allow-list is re-read from disk on <strong>every handshake</strong>, so <code>authorize_client!</code> / <code>revoke_client!</code> take effect <strong>without restarting the gate</strong>. (ZAP only gates <em>new</em> handshakes — an already-connected client stays connected until it reconnects.)</p><h2 id="Keys-live-per-user" tabindex="-1">Keys live per user <a class="header-anchor" href="#Keys-live-per-user" aria-label="Permalink to &quot;Keys live per user {#Keys-live-per-user}&quot;">​</a></h2><p>All CURVE material is stored under your cache directory, mode <code>0600</code>:</p><table tabindex="0"><thead><tr><th style="text-align:right;">File</th><th style="text-align:right;">Role</th></tr></thead><tbody><tr><td style="text-align:right;"><code>~/.cache/kaimon/curve/server.key</code></td><td style="text-align:right;">this host&#39;s server keypair (gates present it)</td></tr><tr><td style="text-align:right;"><code>~/.cache/kaimon/curve/client.key</code></td><td style="text-align:right;">this Kaimon&#39;s client keypair (used to connect out)</td></tr><tr><td style="text-align:right;"><code>~/.cache/kaimon/curve/known_servers</code></td><td style="text-align:right;">pinned server keys — <code>host:port pubkey</code> lines (TOFU)</td></tr><tr><td style="text-align:right;"><code>~/.cache/kaimon/curve/authorized_clients</code></td><td style="text-align:right;">allow-listed client public keys</td></tr></tbody></table><p>Because the keystore is rooted in each user&#39;s private home, two users on one machine get <strong>independent trust domains</strong> for free: under strict mode, a client authorized by one user cannot connect to the other&#39;s CURVE gates.</p><h2 id="TOFU-and-soy-free-mode" tabindex="-1">TOFU and soy-free mode <a class="header-anchor" href="#TOFU-and-soy-free-mode" aria-label="Permalink to &quot;TOFU and soy-free mode {#TOFU-and-soy-free-mode}&quot;">​</a></h2><p>First contact is the one weak point. Under <strong>TOFU</strong> (Trust On First Use — a.k.a. the &quot;leap of faith&quot; model, the same scheme SSH uses for host keys) the client pins whatever server key it sees on the first successful connection and verifies it never changes thereafter. That closes every <em>later</em> MITM, but an attacker present at the <em>very first</em> connection could get their key pinned.</p><p><strong>Soy-free mode</strong> removes even that gap. If you already have SSH access to the gate host, fetch the server&#39;s public key over that <em>already-authenticated</em> channel and pin it <em>before</em> the first ZMQ connection:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonGate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">verify_server_key_via_ssh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gate-host&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10005</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div>',11)),(s(),n(l,null,{default:t(()=>[o(a,{id:"mermaid-112",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20U%20as%20You%20(Kaimon)%0A%20%20%20%20participant%20H%20as%20Gate%20host%20(SSH-trusted)%0A%20%20%20%20Note%20over%20U%2CH%3A%20SSH%20host%20key%20already%20verified%20in%20~%2F.ssh%2Fknown_hosts%0A%20%20%20%20U-%3E%3EH%3A%20ssh%20gate-host%20head%20-n1%20~%2F.cache%2Fkaimon%2Fcurve%2Fserver.key%0A%20%20%20%20H--%3E%3EU%3A%20server%20PUBLIC%20key%20(secret%20never%20leaves%20the%20host)%0A%20%20%20%20U-%3E%3EU%3A%20pin%20host%3Aport%20%E2%86%92%20key%20in%20known_servers%0A%20%20%20%20Note%20over%20U%3A%20no%20leap%20of%20faith%20%E2%80%94%20the%20pin%20is%20bootstrapped%20over%20a%20trusted%20channel%0A%20%20%20%20U-%3E%3EH%3A%20CURVE%20connect%2C%20encrypted%20to%20the%20pinned%20key%0A%20%20%20%20H--%3E%3EU%3A%20handshake%20OK%20%E2%86%92%20pong%20%F0%9F%94%92%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[r(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=i('<p><code>verify_server_key_via_ssh</code> reads only the <strong>first line</strong> of the remote <code>server.key</code> (the public half — the secret never crosses the wire) and reconciles it with your local pin:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Result</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>:pinned</code></td><td style="text-align:right;">no prior pin — bootstrapped from the SSH-fetched key (no leap of faith)</td></tr><tr><td style="text-align:right;"><code>:ok</code></td><td style="text-align:right;">the SSH-fetched key matches your existing pin</td></tr><tr><td style="text-align:right;"><code>:changed</code></td><td style="text-align:right;">the host&#39;s key <strong>differs</strong> from your pin — a rotation, or an attack</td></tr><tr><td style="text-align:right;"><code>:error</code></td><td style="text-align:right;">SSH/read failure — the pin is left untouched</td></tr></tbody></table><p>It&#39;s called <em>soy-free</em> because it&#39;s the antidote to TOFU: you don&#39;t take the mystery dish on faith — you bring your own verified key (the steak, not the tofu). And because the CURVE server key is <em>server-authenticating</em> (the client must encrypt to it; there is no bearer secret to capture), bootstrapping the pin over SSH collapses trust down to &quot;do you already trust SSH to this host?&quot; — which you do, since you SSH there anyway.</p><div class="tip custom-block"><p class="custom-block-title">Defaults assume the standard identity</p><p><code>verify_server_key_via_ssh</code> reads <code>~/.cache/kaimon/curve/server.key</code> and SSHes to <code>host</code> by default. A gate started with an explicit <code>server_secret</code> (not the shared host key), or reachable under a different SSH alias, needs the <code>remote_key_path</code> / <code>ssh_target</code> keyword arguments.</p></div><h2 id="Managing-keys-in-the-TUI" tabindex="-1">Managing keys in the TUI <a class="header-anchor" href="#Managing-keys-in-the-TUI" aria-label="Permalink to &quot;Managing keys in the TUI {#Managing-keys-in-the-TUI}&quot;">​</a></h2><p>The Sessions tab has a CURVE key-management modal — press <strong><code>k</code></strong>:</p><p><img src="https://github.com/kahliburke/Kaimon.jl/releases/download/docs-assets/kaimon_curve.gif" alt=""></p><ul><li><p><strong>Identity</strong> — this instance&#39;s client and server key fingerprints. The full selected key is shown so you can hand it to a remote gate operator for enrollment.</p></li><li><p><strong>Authorized clients</strong> — <code>a</code> to add a client key, <code>d</code> to revoke. Changes apply live (no gate restart).</p></li><li><p><strong>Pinned servers</strong> — <code>u</code> to unpin, <strong><code>s</code> for soy-free verify</strong> (SSH-checks the selected pin). A changed key raises a loud <strong>&quot;SERVER KEY CHANGED&quot;</strong> alert and asks for confirmation before re-pinning.</p></li></ul><p>Encrypted sessions show a 🔒 in the Sessions list and on the Details pane.</p><h2 id="Diagnosing-a-stalled-CURVE-session" tabindex="-1">Diagnosing a stalled CURVE session <a class="header-anchor" href="#Diagnosing-a-stalled-CURVE-session" aria-label="Permalink to &quot;Diagnosing a stalled CURVE session {#Diagnosing-a-stalled-CURVE-session}&quot;">​</a></h2><p>A wrong or missing key fails the handshake <em>silently</em> — in-band it is indistinguishable from the gate being down. So when a TCP session stalls, Kaimon runs a raw TCP-reachability probe and labels <em>why</em> on the Sessions detail line:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Reason</th><th style="text-align:right;">Meaning</th><th style="text-align:right;">Fix</th></tr></thead><tbody><tr><td style="text-align:right;"><code>offline</code></td><td style="text-align:right;">the port refused the connection</td><td style="text-align:right;">the gate is down / not listening</td></tr><tr><td style="text-align:right;"><code>key?</code></td><td style="text-align:right;">reachable, but the pinned-key handshake fails</td><td style="text-align:right;">the server key likely changed — soy-free verify, then re-pin</td></tr><tr><td style="text-align:right;"><code>no pong</code></td><td style="text-align:right;">reachable, no key pinned, no response</td><td style="text-align:right;">if it is a CURVE gate, pin/verify its key</td></tr></tbody></table><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Function</th><th style="text-align:right;">Purpose</th></tr></thead><tbody><tr><td style="text-align:right;"><code>KaimonGate.verify_server_key_via_ssh(host, port; ssh_target, remote_key_path, repin)</code></td><td style="text-align:right;">soy-free: SSH-bootstrap / verify a server pin</td></tr><tr><td style="text-align:right;"><code>KaimonGate.pin_server!(host, port, pubkey)</code></td><td style="text-align:right;">pin a server key (<code>:pinned</code> / <code>:ok</code> / <code>:mismatch</code>)</td></tr><tr><td style="text-align:right;"><code>KaimonGate.unpin_server!(&quot;host:port&quot;)</code></td><td style="text-align:right;">remove a server pin</td></tr><tr><td style="text-align:right;"><code>KaimonGate.known_servers()</code></td><td style="text-align:right;">list all pins as <code>(host:port, pubkey)</code></td></tr><tr><td style="text-align:right;"><code>KaimonGate.authorize_client!(pubkey)</code></td><td style="text-align:right;">add a client to the allow-list (live)</td></tr><tr><td style="text-align:right;"><code>KaimonGate.revoke_client!(pubkey)</code></td><td style="text-align:right;">remove a client from the allow-list (live)</td></tr><tr><td style="text-align:right;"><code>KaimonGate.authorized_clients()</code></td><td style="text-align:right;">list allow-listed client keys</td></tr><tr><td style="text-align:right;"><code>KaimonGate.curve_keypair()</code> / <code>curve_public(secret)</code></td><td style="text-align:right;">generate / derive Z85 keys</td></tr></tbody></table>',14))])}const b=d(p,[["render",g]]);export{f as __pageData,b as default};
